+
+/// __edgebox_debug_last_lookup() - Get last lookup info from C frozen code
+fn getLastLookup(ctx: ?*qjs.JSContext, _: qjs.JSValue, _: c_int, _: [*c]qjs.JSValue) callconv(.c) qjs.JSValue {
