+pub fn init() void {
+    native_registry_init();
+}
+
+/// Clean up the native registry
+pub fn deinit() void {
+    native_registry_deinit();
+}
+
+/// Register native shape functions to globalThis
+/// Called ONCE at WASM initialization
+pub fn register(ctx: *qjs.JSContext) void {
